// models
export interface IThemeState {
  isDarkMode: boolean;
}

@Injectable({ providedIn: "root" })
export class CorThemeService {
  // store
  #state = signal<IThemeState>({
    isDarkMode: false,
  });

  // selectors
  isDarkMode = computed<boolean>(() => !!this.#state()?.isDarkMode);

  // actions
  setIsDarkMode(isDarkMode: boolean) {
    this.#state.update((state: any) => ({ ...state, isDarkMode }));
  }

  // constructor
  constructor() {
    // effect(() => console.log(this.#state()));

    effect(() => {
      document.documentElement.setAttribute(
        "data-theme",
        !!this.isDarkMode() ? "dark" : "light",
      );
    });
  }
}
